const { ApolloServer, gql, PubSub } = require('apollo-server');
const { WebSocketServer } = require('ws');
const jwt = require('jsonwebtoken');
const http = require('http');

const pubsub = new PubSub();
const MESSAGE_ADDED = 'MESSAGE_ADDED';

const typeDefs = gql`
  type Message {
    id: ID!
    content: String!
    roomId: ID!
  }

  type Query {
    messages(roomId: ID!): [Message]
  }

  type Mutation {
    sendMessage(roomId: ID!, content: String!): Message
  }

  type Subscription {
    messageAdded(roomId: ID!): Message
  }
`;

const messages = [];

const resolvers = {
  Query: {
    messages: (parent, { roomId }) => messages.filter(msg => msg.roomId === roomId),
  },
  Mutation: {
    sendMessage: (parent, { roomId, content }, { user }) => {
      if (!user) throw new Error('Unauthorized');
      const message = { id: messages.length + 1, content, roomId };
      messages.push(message);
      pubsub.publish(MESSAGE_ADDED, { messageAdded: message, roomId });
      return message;
    },
  },
  Subscription: {
    messageAdded: {
      subscribe: (parent, { roomId }) => {
        return pubsub.asyncIterator([MESSAGE_ADDED]);
      },
    },
  },
};

const getUserFromToken = (token) => {
  if (token) {
    try {
      return jwt.verify(token, process.env.JWT_SECRET);
    } catch (e) {
      throw new Error('Invalid token');
    }
  }
  return null;
};

const server = new ApolloServer({
  typeDefs,
  resolvers,
  context: ({ req }) => {
    const token = req.headers.authorization || '';
    const user = getUserFromToken(token.replace('Bearer ', ''));
    return { user };
  },
});

const httpServer = http.createServer(server);
const wsServer = new WebSocketServer({ server: httpServer });

server.installSubscriptionHandlers(wsServer);

httpServer.listen({ port: 4000 }, () => {
  console.log('Server ready at http://localhost:4000/graphql');
  console.log(`Subscriptions ready at ws://localhost:4000/graphql`);
});